"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[1720],{82717:e=>{e.exports=JSON.parse('{"tag":{"label":"rabbit health","permalink":"/docs/tags/rabbit-health","allTagsPath":"/docs/tags","count":7,"items":[{"id":"Rabbits/illnesses-and-conditions/common-health-issues","title":"Common Health Issues in Rabbits","description":"An overview of the most common and serious health issues affecting pet rabbits, including the critical emergencies of GI stasis, the importance of dental health, and the high rate of uterine cancer in unspayed females.","permalink":"/docs/Rabbits/illnesses-and-conditions/common-health-issues"},{"id":"Rabbits/health-and-wellness/dental-health","title":"Dental Health in Rabbits","description":"An in-depth guide to dental disease in rabbits, explaining why it is so common, how to recognize the signs of oral pain, and the absolute necessity of a hay-based diet for prevention.","permalink":"/docs/Rabbits/health-and-wellness/dental-health"},{"id":"Rabbits/health-and-wellness/eye-and-vision-issues","title":"Eye & Vision Issues in Rabbits","description":"A guide to common eye and vision issues in rabbits, focusing on the critical link between weepy eyes (epiphora) and underlying dental disease, as well as other conditions like ulcers and abscesses.","permalink":"/docs/Rabbits/health-and-wellness/eye-and-vision-issues"},{"id":"Rabbits/health-and-wellness/gi-health","title":"Gastrointestinal (GI) Health in Rabbits","description":"An in-depth guide to the sensitive gastrointestinal (GI) system of rabbits, covering the causes and signs of the life-threatening emergencies GI stasis and bloat, and the critical role of hay.","permalink":"/docs/Rabbits/health-and-wellness/gi-health"},{"id":"Rabbits/health-and-wellness/parasites","title":"Parasites in Rabbits","description":"A guide to common parasites affecting rabbits, including the severe ear and fur mites, and the neurological parasite E. cuniculi, a primary cause of head tilt.","permalink":"/docs/Rabbits/health-and-wellness/parasites"},{"id":"Rabbits/health-and-wellness/respiratory-issues","title":"Respiratory Issues in Rabbits (\\"Snuffles\\")","description":"An in-depth guide to upper respiratory infections (Snuffles) in rabbits, caused by Pasteurella multocida and other bacteria, covering the signs, progression, and treatment of this common and often chronic condition.","permalink":"/docs/Rabbits/health-and-wellness/respiratory-issues"},{"id":"Rabbits/illnesses-and-conditions/urinary-and-bladder-issues","title":"Urinary and Bladder Issues in Rabbits","description":"An in-depth guide to urinary and bladder issues in rabbits, focusing on the causes and management of excess calcium in the urine (sludge) and the formation of bladder stones.","permalink":"/docs/Rabbits/illnesses-and-conditions/urinary-and-bladder-issues"}],"unlisted":false}}')}}]);